+        assert!(matches!(
+            agent_type_from_db("claude_code"),
+            AgentType::ClaudeCode
+        ));
+        assert!(matches!(agent_type_from_db("gemini"), AgentType::Gemini));
+        assert!(matches!(agent_type_from_db("wezterm"), AgentType::Wezterm));
+    }
