+    #[test]
+    fn snapshot_error_display_messages() {
+        assert_eq!(
+            SnapshotError::InProgress.to_string(),
+            "snapshot already in progress"
+        );
+        assert_eq!(SnapshotError::NoPanes.to_string(), "no panes found");
